import { IsString, IsNumber, IsDateString, IsEnum, Min, MaxDate } from 'class-validator';
import { Type } from 'class-transformer';

export class AgendarPixDto {
  @IsString()
  chavePix: string;

  @IsEnum(['CPF', 'TELEFONE', 'EMAIL', 'ALEATORIA'])
  tipoChave: TipoChavePix;

  @IsNumber()
  @Min(0.01, { message: 'Valor deve ser positivo' })
  valor: number;

  @IsDateString()
  @Type(() => Date)
  @MaxDate(
    () => addDays(new Date(), 90),
    { message: 'Data nao pode exceder 90 dias' }
  )
  dataAgendada: Date;

  @IsString()
  descricao?: string;
}

@Cron('*/1 * * * *') // a cada minuto
async executarAgendamentosPendentes() {
  const agora = new Date();
  const agendamentos = await this.repo
    .createQueryBuilder('a')
    .where('a.status = :status', { status: 'AGENDADO' })
    .andWhere('a.dataAgendada <= :agora', { agora })
    .setLock('pessimistic_write')
    .limit(50)
    .getMany();

  for (const ag of agendamentos) {
    if (!this.dentroJanelaExecucao(ag, agora)) continue;
    await this.processar(ag);
  }
}

export function PixAgendarScreen() {
  const [dataAgendada, setDataAgendada] = useState<Date>();
  const { autenticar } = useBiometricAuth();

  async function handleAgendar() {
    if (!dataAgendada) return;
    const ok = await autenticar('Confirmar agendamento PIX');
    if (!ok) return;

    await pixApi.agendarPix({
      chavePix: chave,
      valor,
      dataAgendada,
      descricao,
    });

    navigate('PixAgendamentoConfirmado');
  }

  return (
    <Screen testID="pix-agendar-screen">
      {/* ... */}
    </Screen>
  );
}

async notificarSucesso(agendamento: PixAgendamento) {
  await this.emailService.enviar({
    para: agendamento.cliente.email,
    template: 'pix-agendado-sucesso',
    dados: {
      nome: agendamento.cliente.nome,
      valor: formatarMoeda(agendamento.valor),
      destinatario: agendamento.chavePix,
      data: formatarData(agendamento.dataAgendada),
    },
  });

  await this.pushService.enviar({
    deviceToken: agendamento.cliente.fcmToken,
    titulo: 'PIX agendado executado',
    corpo: `R$ ${formatarMoeda(agendamento.valor)} para ${agendamento.chavePix}`,
  }).catch(err => this.logger.warn('Push falhou', err));
}

