describe('PixAgendamentoService', () => {
  describe('agendar', () => {
    it('deve criar agendamento valido com data futura', async () => {
      const dto = factory.agendarPixDto({ dataAgendada: addDays(new Date(), 5) });
      const resultado = await service.agendar(dto, cliente);
      expect(resultado.id).toBeDefined();
      expect(resultado.status).toBe('AGENDADO');
    });

    it('deve rejeitar agendamento com data passada', async () => {
      const dto = factory.agendarPixDto({ dataAgendada: subDays(new Date(), 1) });
      await expect(service.agendar(dto, cliente))
        .rejects.toThrow(DataInvalidaException);
    });

    it('deve rejeitar valor zero ou negativo', async () => {
      const dto = factory.agendarPixDto({ valor: 0 });
      await expect(service.agendar(dto, cliente))
        .rejects.toThrow(ValorInvalidoException);
    });
  });
});

describe('PixSchedulerService - integracao', () => {
  it('deve processar agendamentos pendentes respeitando janela', async () => {
    const ag = await criarAgendamento({
      dataAgendada: new Date(),
      status: 'AGENDADO',
      timezone: 'America/Sao_Paulo',
    });

    jest.useFakeTimers().setSystemTime(new Date('2026-05-22T15:00:00-03:00'));

    await service.executarAgendamentosPendentes();

    const atualizado = await repo.findOne(ag.id);
    expect(atualizado.status).toBe('EXECUTADO');
  });
});
